local LxBaseCtrl = require("LApp.controller.LxBaseCtrl")
---@class LxWarTempleCtrl:LxBaseCtrl
local LxWarTempleCtrl = classX("LxWarTempleCtrl", LxBaseCtrl)

function LxWarTempleCtrl:Initialize()
    LxBaseCtrl.Initialize(self)
end

function LxWarTempleCtrl:Dispose()
    LxBaseCtrl.Dispose(self)
end

---@return V_Item[]
function LxWarTempleCtrl:GetAlterAwardItem()
    if not self._alterAward then
        local alterAward = GameTable.BattleTempleConfigRef.alterAward
        self._alterAward = LxDataHelper.ParseItemStrList(alterAward)
    end
    return self._alterAward
end


---@return V_Item[]
function LxWarTempleCtrl:GetDailyRewardItem()
    local warTempleInfo = ModuleCenter.WarTemple:GetWarTempleInfo()
    if not warTempleInfo then
        return self:GetAlterAwardItem()
    end
    return self:GetWarTempleAwardItems(warTempleInfo.palace,warTempleInfo.rank)
end

---@return V_Item[]
function LxWarTempleCtrl:GetWarTempleAwardItems(palace,rank)
    if palace == 0 or rank == 0 then
        return self:GetAlterAwardItem()
    end

    local dailyReward = self._dailyReward
    if not dailyReward then
        dailyReward = {}
        for k,v in pairs(GameTable.BattleTempleAwardRef) do
            if v.sort == 1 then
                local dailyRewardItemMap = dailyReward[v.PalacerId]
                if not dailyRewardItemMap then
                    dailyRewardItemMap = {}
                    dailyReward[v.PalacerId] = dailyRewardItemMap
                end
                dailyRewardItemMap[v.rank] = LxDataHelper.ParseItemStrList(v.reward)
            end
        end
        self._dailyReward = dailyReward
    end
    local dailyRewardItemMap = dailyReward[palace]
    if not dailyRewardItemMap then return {} end

    return dailyRewardItemMap[rank] or {}
end


---@return V_WarTemplePalaceRef[]
function LxWarTempleCtrl:GetSortWarTemplePalaceRefs()
    ---@type V_WarTemplePalaceRef[]
    local sortWarTemplePalaceRefs = self._sortWarTemplePalaceRefs
    if not sortWarTemplePalaceRefs then
        sortWarTemplePalaceRefs = {}
        for k,v in pairs(GameTable.BattleTemplePalaceRef) do
            table.insert(sortWarTemplePalaceRefs,v)
        end
        table.sort(sortWarTemplePalaceRefs,function(a,b)
            return a.sort < b.sort
        end)
        self._sortWarTemplePalaceRefs = sortWarTemplePalaceRefs
    end
    return sortWarTemplePalaceRefs
end

