function LxWarTempleCtrl:GetSortWarTempleCombatAwardRefs()
    ---@type V_WarTempleCombatAwardRef[]
    local sortWarTempleCombatAwardRefs = self._sortWarTempleCombatAwardRefs
    if not sortWarTempleCombatAwardRefs then
        sortWarTempleCombatAwardRefs = {}
        for k,v in pairs(GameTable.BattleTempleCombatAwardRef) do
            table.insert(sortWarTempleCombatAwardRefs,v)
        end
        table.sort(sortWarTempleCombatAwardRefs,function(a,b)
            return a.sort < b.sort
        end)
        self._sortWarTempleCombatAwardRefs = sortWarTempleCombatAwardRefs
    end
    return sortWarTempleCombatAwardRefs
end

function LxWarTempleCtrl:GetFirstWarTemplePalaceName()
    local refs = self:GetSortWarTemplePalaceRefs()
    local firstRef = refs[1]
    return firstRef and I18nText(firstRef.name) or ""
end

function LxWarTempleCtrl:GetInitWarTempleEeffigyRef(lv)
    local lv2EeffigyRefMap = self._lv2EeffigyRefMap
    if not lv2EeffigyRefMap then
        lv2EeffigyRefMap = {}
        self._lv2EeffigyRefMap = lv2EeffigyRefMap
    end
    local lvEeffigyRef = lv2EeffigyRefMap[lv]
    if not lvEeffigyRef then
        for k,v in pairs(GameTable.BattleTempleEeffigyRef) do
            if v.lvNow == lv then
                lvEeffigyRef = {
                    refId = k,
                    lvNow = lv,
                    lvNext = v.lvNext,
                    attr = LxDataHelper.ParseAttrStr(v.attr,","),
                    attrChange = LxDataHelper.ParseAttrStr(v.attrChange,","),
                    upNeed = LxDataHelper.ParseItemStrList(v.upNeed,",")
                }
                break
            end
        end
        lv2EeffigyRefMap[lv] = lvEeffigyRef
    end
    return lvEeffigyRef
end

function LxWarTempleCtrl:GetWarTempleEeffigyMaxLv()
    if not self._warTempleEeffigyMaxLv then
        for k,v in pairs(GameTable.BattleTempleEeffigyRef) do
            if v.lvNext == -1 then
                self._warTempleEeffigyMaxLv = v.lvNow
                break
            end
        end
    end
    return self._warTempleEeffigyMaxLv
end


function LxWarTempleCtrl:GetWarTempleEeffigyShowAttrs()
    local egfffigyLv = ModuleCenter.WarTemple:GetInfoEgfffigyLv()
    local initRef = self:GetInitWarTempleEeffigyRef(egfffigyLv)
    if not initRef then return {} end

    local resultList = {}
    ---@type V_Attr[]
    local attr = initRef.attr
    ---@type V_Attr[]
    local attrChange = initRef.attrChange
    if #attr > 0 then
        local map = self:AttrList2Map(attrChange)
        local refId
        ---@type V_Attr
        local addItem
        for i,v in ipairs(attr) do
            refId = v.refId
            addItem = map[refId]
            table.insert(resultList,{
                refId = refId,
                baseValue = v.value,
                addValue = addItem and addItem.value,
                tar = v.tar,
                showAdd = addItem ~= nil,
            })
        end
    else
        for i,v in ipairs(attrChange) do
            table.insert(resultList,{
                refId = v.refId,
                baseValue = 0,
                addValue = v.value,
                tar = v.tar,
                showAdd = true,
            })
        end
    end
    return resultList
end

---@param attrList V_Attr[]
function LxWarTempleCtrl:AttrList2Map(attrList)
    if #attrList < 1 then return {} end

    local attrMap = {}
    for i,v in ipairs(attrList) do
        attrMap[v.refId] = v
    end
    return attrMap
end


---@return V_Item[]
function LxWarTempleCtrl:GetWarTempleEeffigyShowUpNeeds()
    local egfffigyLv = ModuleCenter.WarTemple:GetInfoEgfffigyLv()
    local initRef = self:GetInitWarTempleEeffigyRef(egfffigyLv)
    if not initRef then return {} end

    return initRef.upNeed or {}
end

function LxWarTempleCtrl:GetZeroRank()
    local max = 0
    for k, v in pairs(GameTable.BattleTempleMatchRef) do
        max = math.max(max, v.rankSectionMin)
    end
    return max + 1
end


function LxWarTempleCtrl:GetChallengeNumConsumes()
    if not self._challengeNumConsumes then
        local list = {}
        local challengeNumConsume = GameTable.BattleTempleConfigRef.challengeNumConsume
        challengeNumConsume = string.split(challengeNumConsume,";")
        local iType = ThingType.Item
        for i,v in ipairs(challengeNumConsume) do
            v = string.split(v,"=")
            table.insert(list,{
                type = iType,
                refId = Item_Ids.Diamond,
                num = checknumber(v[2]),
                payTime = checknumber(v[1]),
            })
        end
        self._challengeNumConsumes = list
    end
    return self._challengeNumConsumes
end










function LxWarTempleCtrl:CheckRewardRed()
    if self:CheckPalaceRewardRed() then return true end
    if self:CheckRankRewardRed() then return true end
    return false
end

function LxWarTempleCtrl:GetRewardRedNum(rewardType)
    local redNum = 0
    if rewardType == 1 then
        redNum = self:GetPalaceRewardRedNum()
    elseif rewardType == 2 then
        redNum = self:GetRankRewardRedNum()
    end
    return redNum
end

function LxWarTempleCtrl:GetPalaceRewardRedNum()
    local canGetState = RewardStateEnums.CanGet
    local warTempleModule = ModuleCenter.WarTemple
    local canGetNum = 0
    local refs = self:GetSortWarTemplePalaceRefs()
    for i,v in ipairs(refs) do
        if warTempleModule:GetPalaceRewardState(v.refId) == canGetState then
            canGetNum = canGetNum + 1
        end
    end
    return canGetNum
end

function LxWarTempleCtrl:CheckPalaceRewardRed()
    return self:GetPalaceRewardRedNum() > 0
end

function LxWarTempleCtrl:GetRankRewardRedNum()
    local canGetState = RewardStateEnums.CanGet
    local warTempleModule = ModuleCenter.WarTemple
    local canGetNum = 0
    local refs = self:GetSortWarTempleCombatAwardRefs()
    for i,v in ipairs(refs) do
        if warTempleModule:GetTargetRewardState(v.refId) == canGetState then
            canGetNum = canGetNum + 1
        end
    end
    return canGetNum
end

function LxWarTempleCtrl:CheckRankRewardRed()
    return self:GetRankRewardRedNum() > 0
end


---@return number 状态 0：可升级，-1：已满级，-2：无配置道具消耗，-3：道具不足
function LxWarTempleCtrl:CheckStatuesIsCanUpLv(extraData)
    extraData = extraData or {}

    local egfffigyLv = ModuleCenter.WarTemple:GetInfoEgfffigyLv()
    local warTempleEeffigyMaxLv = self:GetWarTempleEeffigyMaxLv()
    if egfffigyLv >= warTempleEeffigyMaxLv then return -1 end

    local payItemList = self:GetWarTempleEeffigyShowUpNeeds()
    if #payItemList < 1 then return -2 end

    if not CtrlCenter.Item:CheckItemListEnough(payItemList,extraData.showTips,extraData.uiName) then
        return -3
    end

    return 0
end

function LxWarTempleCtrl:CheckHasRewardGet()
    if self:CheckHasWarTemplePalaceRewardGet() then return true end
    if self:CheckHasWarTempleCombatAwardRewardGet() then return true end
    return false
end

function LxWarTempleCtrl:CheckHasWarTemplePalaceRewardGet()
    local warTempleModule = ModuleCenter.WarTemple
    local refs = self:GetSortWarTemplePalaceRefs()
    for i,v in ipairs(refs) do
        if warTempleModule:GetPalaceRewardState(v.refId) == RewardStateEnums.CanGet then
            return true
        end
    end
    return false
end

function LxWarTempleCtrl:CheckHasWarTempleCombatAwardRewardGet()
    local warTempleModule = ModuleCenter.WarTemple
    local refs = self:GetSortWarTempleCombatAwardRefs()
    for i,v in ipairs(refs) do
        if warTempleModule:GetTargetRewardState(v.refId) == RewardStateEnums.CanGet then
            return true
        end
    end
    return false
end


return LxWarTempleCtrl